import{_ as e,o as l,c as i,a5 as t}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0045：PCS LCL 滤波器与有源阻尼","description":"","frontmatter":{"title":"教程 0045：PCS LCL 滤波器与有源阻尼","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0045-pcs-lcl-filter-active-damping.html","status":"learning","visibility":"public","summary":"Imported from 0045-pcs-lcl-filter-active-damping.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0045-pcs-lcl-filter-active-damping.md","filePath":"content/power/lessons/0045-pcs-lcl-filter-active-damping.md","lastUpdated":null}'),r={name:"content/power/lessons/0045-pcs-lcl-filter-active-damping.md"};function o(c,a,n,p,s,d){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="教程-0045-pcs-lcl-滤波器与有源阻尼" tabindex="-1">教程 0045：PCS LCL 滤波器与有源阻尼 <a class="header-anchor" href="#教程-0045-pcs-lcl-滤波器与有源阻尼" aria-label="Permalink to &quot;教程 0045：PCS LCL 滤波器与有源阻尼&quot;">​</a></h1><p>中文主讲。一个概念：LCL 滤波器能强力抑制开关纹波，但必须处理谐振。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只讲公开滤波器模型，不记录并网认证指标、真实电感电容参数或阻尼系数。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>LCL 滤波器（LCL filter）由变流器侧电感、滤波电容和电网侧电感组成。相比单电感 L，它对高频开关纹波衰减更快，但会形成谐振峰，需要有源阻尼（active damping）或无源阻尼抑制。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>PCS 并网口必须限制电流谐波。LCL 可以用较小总电感获得较好高频衰减，但谐振如果处理不好，会在电流环中放大噪声甚至引发不稳定。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>LCL 像两个弹簧中间夹一个质量块。它很会隔离高频振动，但中间质量块有自己的共振频率。阻尼就是给这个振动加刹车。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>f_res = 1 / (2*pi) * sqrt((L1 + L2) / (L1 * L2 * Cf)) u_ref = current_loop_output - K_ad * i_c_or_v_c_feedback</p><p>有源阻尼常用电容电流反馈、电容电压微分反馈或数字滤波实现，目标是压低谐振峰。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>扫频观察 LCL 传递函数。先不加阻尼，标出谐振峰；再加入电容电流反馈，观察谐振峰下降。</p><p>产物</p><ul><li>一张 L 与 LCL 高频衰减对比图。</li><li>一张加阻尼前后的谐振峰对比图。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件可能采样逆变器侧电流、电网侧电流或电容电流。控制代码中常见 <code>capacitor_current_feedback</code>、<code>notch_filter</code>、<code>active_damping_gain</code> 和采样延时补偿。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**LCL 一定比 L 更稳定。 **纠正：**LCL 滤波更强，但谐振更难处理。</li><li>**误解：**无源阻尼没有代价。 **纠正：**电阻阻尼会带来损耗。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能写出 LCL 谐振频率的影响因素。</li><li>能说明为什么有源阻尼需要额外反馈或滤波。</li><li>能区分逆变器侧电流和电网侧电流控制。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>谐振频率太接近控制带宽会发生什么？</li><li>采样延时会如何影响有源阻尼？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>PCS 并网电流控制一般反馈哪一路电流？LCL 阻尼入口在哪里看？</li><li>我不记录内部滤波参数，只确认阅读路径。</li></ul><p>**下一步：**连接储能电池侧 DC-DC 和 PCS 模式状态机。</p><p>源稿：<code>concepts/pcs/lcl-filter-active-damping.md</code></p><p>上一节：教程 0044：PCS 构网型 V/f 与下垂控制下一节：教程 0046：PCS 储能 DC-DC 与模式状态机</p>',31)])])}const u=e(r,[["render",o]]);export{_ as __pageData,u as default};
